    token = input("ENTER JWT TOKEN: ")
    threads = []

    for item_id in items_to_send:
        encrypted_payload = wishlistItems_payload(item_id)
        thread = threading.Thread(target=add_item, args=(token, encrypted_payload, item_id))
        threads.append(thread)
        thread.start()

    # انتظار انتهاء جميع الخيوط
    for thread in threads:
        thread.join()

